import { useState, useEffect, useCallback } from 'react';
import { useAuth } from '../context/SupabaseContext';
import { BADGES, type BadgeDefinition } from '../config/badges';

export interface Achievement {
  id: string;
  user_id: string;
  badge_id: string;
  earned_at: string;
}

export function useAchievements() {
  const { user, supabase, isLoading: authLoading } = useAuth();
  const [achievements, setAchievements] = useState<Achievement[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [newlyEarned, setNewlyEarned] = useState<BadgeDefinition | null>(null);
  const [streakCurrent, setStreakCurrent] = useState(0);
  const [streakBest, setStreakBest] = useState(0);

  // Fetch all achievements
  const fetchAchievements = useCallback(async () => {
    if (!user) {
      setAchievements([]);
      setIsLoading(false);
      return;
    }

    try {
      const { data, error } = await supabase
        .from('user_achievements')
        .select('*')
        .eq('user_id', user.id)
        .order('earned_at', { ascending: false });

      if (!error && data) {
        setAchievements(data);
      }
    } finally {
      setIsLoading(false);
    }
  }, [user, supabase]);

  // Load on mount
  useEffect(() => {
    if (authLoading) return;
    fetchAchievements();
  }, [authLoading, fetchAchievements]);

  // Load streak data
  const loadStreak = useCallback(async () => {
    if (!user) return;

    const { data } = await supabase
      .from('user_profiles')
      .select('streak_current, streak_best, last_active_date')
      .eq('user_id', user.id)
      .maybeSingle();

    if (data) {
      setStreakCurrent(data.streak_current || 0);
      setStreakBest(data.streak_best || 0);
    }
  }, [user, supabase]);

  useEffect(() => {
    if (authLoading || !user) return;
    loadStreak();
  }, [authLoading, user, loadStreak]);

  // Award a badge (idempotent)
  const awardBadge = useCallback(async (badgeId: string) => {
    if (!user) return false;
    const badge = BADGES[badgeId];
    if (!badge) return false;
    if (achievements.some(a => a.badge_id === badgeId)) return false;

    const { error } = await supabase
      .from('user_achievements')
      .insert({ user_id: user.id, badge_id: badgeId });

    if (!error) {
      setNewlyEarned(badge);
      await fetchAchievements();
      return true;
    }
    return false;
  }, [user, supabase, achievements, fetchAchievements]);

  // Update streak
  const updateStreak = useCallback(async () => {
    if (!user) return;

    const today = new Date().toISOString().slice(0, 10);

    const { data: profile } = await supabase
      .from('user_profiles')
      .select('streak_current, streak_best, last_active_date')
      .eq('user_id', user.id)
      .maybeSingle();

    if (!profile) return;

    const lastActive = profile.last_active_date;

    // Already logged today
    if (lastActive === today) {
      setStreakCurrent(profile.streak_current || 0);
      setStreakBest(profile.streak_best || 0);
      return;
    }

    const yesterday = new Date(Date.now() - 86400000).toISOString().slice(0, 10);
    let newStreak: number;

    if (lastActive === yesterday) {
      newStreak = (profile.streak_current || 0) + 1;
    } else {
      newStreak = 1; // streak broken
    }

    const newBest = Math.max(newStreak, profile.streak_best || 0);

    await supabase.from('user_profiles').update({
      streak_current: newStreak,
      streak_best: newBest,
      last_active_date: today,
    }).eq('user_id', user.id);

    setStreakCurrent(newStreak);
    setStreakBest(newBest);

    // Check streak badges
    if (newStreak >= 3) await awardBadge('streak_starter');
    if (newStreak >= 7) await awardBadge('streak_champion');
    if (newStreak >= 30) await awardBadge('streak_legend');
  }, [user, supabase, awardBadge]);

  const dismissNewBadge = useCallback(() => setNewlyEarned(null), []);

  const hasBadge = useCallback((badgeId: string) => {
    return achievements.some(a => a.badge_id === badgeId);
  }, [achievements]);

  return {
    achievements,
    isLoading,
    newlyEarned,
    dismissNewBadge,
    awardBadge,
    updateStreak,
    hasBadge,
    streakCurrent,
    streakBest,
    refetch: fetchAchievements,
  };
}
